// Handler creates http.Handler with routing matching OpenAPI spec.
func Handler(si ServerInterface) http.Handler {
	return HandlerWithOptions(si, ChiServerOptions{})
}

type ChiServerOptions struct {
	BaseURL          string
	BaseRouter       chi.Router
	Middlewares      []MiddlewareFunc
	ErrorHandlerFunc func(w http.ResponseWriter, r *http.Request, err error)
}

// HandlerFromMux creates http.Handler with routing matching OpenAPI spec based on the provided mux.
func HandlerFromMux(si ServerInterface, r chi.Router) http.Handler {
	return HandlerWithOptions(si, ChiServerOptions{
		BaseRouter: r,
	})
}

func HandlerFromMuxWithBaseURL(si ServerInterface, r chi.Router, baseURL string) http.Handler {
	return HandlerWithOptions(si, ChiServerOptions{
		BaseURL:    baseURL,
		BaseRouter: r,
	})
}

// HandlerWithOptions creates http.Handler with additional options
func HandlerWithOptions(si ServerInterface, options ChiServerOptions) http.Handler {
	r := options.BaseRouter

	if r == nil {
		r = chi.NewRouter()
	}
	if options.ErrorHandlerFunc == nil {
		options.ErrorHandlerFunc = func(w http.ResponseWriter, r *http.Request, err error) {
			http.Error(w, err.Error(), http.StatusBadRequest)
		}
	}
	wrapper := ServerInterfaceWrapper{
		Handler:            si,
		HandlerMiddlewares: options.Middlewares,
		ErrorHandlerFunc:   options.ErrorHandlerFunc,
	}

	r.Group(func(r chi.Router) {
		r.Get(options.BaseURL+"/gears", wrapper.ListGears)
	})
	r.Group(func(r chi.Router) {
		r.Get(options.BaseURL+"/gears/certification/{type}/{authority}/{id}", wrapper.ListByCertification)
	})
	r.Group(func(r chi.Router) {
		r.Get(options.BaseURL+"/gears/firmware/{depot}/{channel}", wrapper.ListByFirmware)
	})
	r.Group(func(r chi.Router) {
		r.Get(options.BaseURL+"/gears/imei/{tac}/{serial}", wrapper.ResolveByIMEI)
	})
	r.Group(func(r chi.Router) {
		r.Get(options.BaseURL+"/gears/label/{key}/{value}", wrapper.ListByLabel)
	})
	r.Group(func(r chi.Router) {
		r.Get(options.BaseURL+"/gears/sn/{sn}", wrapper.ResolveBySN)
	})
	r.Group(func(r chi.Router) {
		r.Delete(options.BaseURL+"/gears/{publicKey}", wrapper.DeleteGear)
	})
	r.Group(func(r chi.Router) {
		r.Get(options.BaseURL+"/gears/{publicKey}", wrapper.GetGear)
	})
	r.Group(func(r chi.Router) {
		r.Get(options.BaseURL+"/gears/{publicKey}/config", wrapper.GetGearConfig)
	})
	r.Group(func(r chi.Router) {
		r.Put(options.BaseURL+"/gears/{publicKey}/config", wrapper.PutGearConfig)
	})
	r.Group(func(r chi.Router) {
		r.Get(options.BaseURL+"/gears/{publicKey}/info", wrapper.GetGearInfo)
	})
	r.Group(func(r chi.Router) {
		r.Get(options.BaseURL+"/gears/{publicKey}/ota", wrapper.GetGearOTA)
	})
	r.Group(func(r chi.Router) {
		r.Get(options.BaseURL+"/gears/{publicKey}/runtime", wrapper.GetGearRuntime)
	})
	r.Group(func(r chi.Router) {
		r.Post(options.BaseURL+"/gears/{publicKey}:approve", wrapper.ApproveGear)
	})
	r.Group(func(r chi.Router) {
		r.Post(options.BaseURL+"/gears/{publicKey}:block", wrapper.BlockGear)
	})
	r.Group(func(r chi.Router) {
		r.Post(options.BaseURL+"/gears/{publicKey}:refresh", wrapper.RefreshGear)
	})

	return r
}

