func (sh *strictHandler) RefreshGear(w http.ResponseWriter, r *http.Request, publicKey PublicKey) {
	var request RefreshGearRequestObject

	request.PublicKey = publicKey

	handler := func(ctx context.Context, w http.ResponseWriter, r *http.Request, request interface{}) (interface{}, error) {
		return sh.ssi.RefreshGear(ctx, request.(RefreshGearRequestObject))
	}
	for _, middleware := range sh.middlewares {
		handler = middleware(handler, "RefreshGear")
	}

	response, err := handler(r.Context(), w, r, request)

	if err != nil {
		sh.options.ResponseErrorHandlerFunc(w, r, err)
	} else if validResponse, ok := response.(RefreshGearResponseObject); ok {
		if err := validResponse.VisitRefreshGearResponse(w); err != nil {
			sh.options.ResponseErrorHandlerFunc(w, r, err)
		}
	} else if response != nil {
		sh.options.ResponseErrorHandlerFunc(w, r, fmt.Errorf("unexpected response type: %T", response))
	}
}
